// CRM Module Handler  src/js/crm/crm-handler.js
                       
import { initDashboard } from './dashboard';

class CRMHandler {
  constructor() {
    this.modules = new Map();
    this.initialized = false;
  }

  init() {
    if (this.initialized) return;
    
    // Registrar módulos
    this.registerModule('dashboard', initDashboard);

    // Inicializar módulos según la página actual
    this.initializeCurrentPage();
    
    this.initialized = true;
  }

  registerModule(name, initFn) {
    if (!initFn) {
      console.warn(`Module ${name} initialization function is undefined`);
      return;
    }
    this.modules.set(name, initFn);
  }

  initializeCurrentPage() {
    const pageModules = document.body.dataset.crmModules;
    if (!pageModules) return;

    pageModules.split(',').forEach(moduleName => {
      const initFn = this.modules.get(moduleName.trim());
      if (initFn) {
        try {
          initFn();
        } catch (error) {
          console.error(`Error initializing CRM module ${moduleName}:`, error);
        }
      }
    });
  }
}

// Crear y exportar una instancia única
const crmHandler = new CRMHandler();

// Inicializar cuando el DOM esté listo
if (typeof document !== 'undefined') {
  document.addEventListener('DOMContentLoaded', () => {
    crmHandler.init();
  });
}

export default crmHandler;
